// LESSON: Set and Uniqueness - Reference Page 2.
// You will learn: Model uniqueness with HashSet, LinkedHashSet, TreeSet, and comparators.
import java.util.Comparator;
import java.util.HashSet;
import java.util.LinkedHashSet;
import java.util.Set;
import java.util.TreeSet;

class SetUniquenessReference {
  public static void main(String[] args) {
    example1RejectDuplicates();
    example2OrderChoices();
    example3ComparatorUniqueness();
  }

  static void example1RejectDuplicates() {
    Set<String> seen = new HashSet<>();
    boolean firstAda = seen.add("Ada");
    boolean secondAda = seen.add("Ada");
    boolean hasAda = seen.contains("Ada");
    System.out.println(firstAda + " " + secondAda + " " + hasAda);
  }

  static void example2OrderChoices() {
    Set<String> linked = new LinkedHashSet<>();
    linked.add("third");
    linked.add("first");
    linked.add("second");
    Set<String> sorted = new TreeSet<>();
    sorted.add("third");
    sorted.add("first");
    sorted.add("second");
    System.out.println(linked + " " + sorted);
  }

  static void example3ComparatorUniqueness() {
    Set<String> byLength = new TreeSet<>(Comparator.comparingInt(String::length));
    boolean addedCat = byLength.add("cat");
    boolean addedDog = byLength.add("dog");
    boolean addedLion = byLength.add("lion");
    System.out.println(addedCat + " " + addedDog + " " + addedLion + " " + byLength);
  }
}
